  // Canonicalize via URL parser (handles 0::1 -> ::1, ::127.0.0.1 -> ::7f00:1, etc.)
  try {
    const parsed = new URL(`http://${h.includes(":") ? `[${h}]` : h}`);
    h = parsed.hostname.replace(/^\[|\]$/g, "").toLowerCase();
  } catch {
    // fallback to original if unparseable
  }

